import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { FiMenu, FiX, FiChevronDown, FiUser, FiUsers } from 'react-icons/fi';
import './Navigation.css';

const Navigation = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [user, setUser] = useState(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const profileRef = useRef(null);
  const [isEvalOpen, setIsEvalOpen] = useState(false);
  const evalRef = useRef(null);
  const location = useLocation();
  const navigate = useNavigate();

  const isEvalActive =
    location.pathname === '/evaluate' ||
    location.pathname === '/EvaluateBatch';

  // ✅ TOKEN CHECK (MAIN FIX)
  useEffect(() => {
    const token = localStorage.getItem("token");
    if (token) {
      setUser({ name: "User" }); // dummy name
    }
  }, []);

  // close profile dropdown
  useEffect(() => {
    const handler = (e) => {
      if (profileRef.current && !profileRef.current.contains(e.target)) {
        setIsProfileOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // close eval dropdown
  useEffect(() => {
    const handler = (e) => {
      if (evalRef.current && !evalRef.current.contains(e.target)) {
        setIsEvalOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const handleMobileClose = () => setIsMobileMenuOpen(false);

  return (
    <nav className="navbar">
      <div className="navbar-container">

        <Link to="/" className="navbar-logo">
          📝 AI Examiner
        </Link>

        <button
          className="mobile-menu-toggle"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <FiX size={24} /> : <FiMenu size={24} />}
        </button>

        <ul className={`nav-menu ${isMobileMenuOpen ? 'active' : ''}`}>

          {/* Home */}
          <li className="nav-item">
            <Link to="/" className="nav-link">Home</Link>
          </li>

          {/* ✅ Logged in menu */}
          {user && (
            <>
              <li className="nav-item">
                <Link to="/dashboard" className="nav-link">Dashboard</Link>
              </li>

              <li className="nav-item">
                <Link to="/management" className="nav-link">Management</Link>
              </li>

              <li className="nav-item">
                <Link to="/history" className="nav-link">History</Link>
              </li>

              {/* Evaluate */}
              <li className="nav-item eval-item" ref={evalRef}>

                <button
                  className={`nav-link nav-link-primary eval-desktop-btn ${isEvalActive ? 'active' : ''}`}
                  onClick={() => setIsEvalOpen((prev) => !prev)}
                >
                  Evaluate Now <FiChevronDown size={14} />
                </button>

                {isEvalOpen && !isMobileMenuOpen && (
                  <div className="eval-dropdown">
                    <button
                      className="eval-dd-item"
                      onClick={() => navigate('/evaluate')}
                    >
                      <FiUser /> Single Student
                    </button>

                    <button
                      className="eval-dd-item"
                      onClick={() => navigate('/EvaluateBatch')}
                    >
                      <FiUsers /> Entire Class
                    </button>
                  </div>
                )}
              </li>
            </>
          )}

          {/* ❌ Not logged in */}
          {!user && (
            <li className="nav-item">
              <button
                className="nav-link nav-link-primary"
                onClick={() => navigate("/")}
              >
                Login
              </button>
            </li>
          )}

          {/* 👤 Profile */}
          {user && (
            <li className="nav-item profile-item" ref={profileRef}>
              <div onClick={() => setIsProfileOpen(!isProfileOpen)}>
                👤 {user.name}
              </div>

              {isProfileOpen && (
                <div className="profile-dropdown">
                  <p>Welcome back 👋</p>

                  <button
                    onClick={() => {
                      localStorage.removeItem("token");
                      window.location.reload();
                    }}
                  >
                    Logout
                  </button>
                </div>
              )}
            </li>
          )}

        </ul>
      </div>
    </nav>
  );
};

export default Navigation;
